using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class AsyncDownloadController : ControllerBase
    {
        private readonly global::IAsyncDownloadService iAsyncDownloadService;
        public AsyncDownloadController(global::IAsyncDownloadService iAsyncDownloadService)
        {
            this.iAsyncDownloadService = iAsyncDownloadService;
        }

        [Route("GetFileAsync/{id}")]
        [HttpGet]
        public async global::System.Threading.Tasks.Task<global::Microsoft.AspNetCore.Mvc.IActionResult> GetFileAsync([FromRoute] int id)
        {
            var __sb_result = await this.iAsyncDownloadService.GetFileAsync(id);
            this.HttpContext.Response.RegisterForDispose(__sb_result);
            return this.File(__sb_result.Stream, __sb_result.ContentType, __sb_result.FileName);
        }
    }
}
